<template><div class="page"><h2 class="title">优化任务管理</h2><div class="section"><table><thead><tr><th>标题</th><th>建议</th><th>预计节能(kWh)</th><th>设备组</th><th>状态</th><th>操作</th></tr></thead><tbody><tr v-for="t in tasks" :key="t.id"><td>{{t.title}}</td><td>{{t.suggestion}}</td><td>{{t.expected_saving_kwh?.toLocaleString()}}</td><td>{{t.device_group}}</td><td><span class="badge" :class="t.status==='completed'?'badge-success':t.status==='in_progress'?'badge-warning':'badge-info'">{{t.status==='completed'?'已完成':t.status==='in_progress'?'进行中':'待处理'}}</span></td><td><button v-if="t.status==='pending'" class="btn btn-primary btn-sm" @click="complete(t)">完成</button></td></tr></tbody></table></div></div></template><script setup>import { ref,onMounted } from 'vue';import { useEnergyStore } from '../store/energy'
const store=useEnergyStore(),tasks=ref([])
function complete(t){ t.status='completed'; alert(`任务"${t.title}"已完成!`) }
onMounted(async()=>{ const d=await store.fetchJSONRaw('/api/efficiency/optimization_tasks')||{}; tasks.value=d.tasks||[] })
</script><style scoped>.page{display:flex;flex-direction:column;gap:16px}.title{font-size:18px;color:#333}.section{background:#fff;border:1px solid #e8eaed;border-radius:10px;padding:20px;overflow-x:auto}table{width:100%;border-collapse:collapse;font-size:13px}th,td{padding:10px 14px;border-bottom:1px solid #f0f0f0}th{background:#f5f7fa;color:#666;font-weight:600}.badge{padding:2px 8px;border-radius:4px;font-size:11px}.badge-success{background:#e6f7f1;color:#00a870}.badge-warning{background:#fff3e0;color:#f57c00}.badge-info{background:#e3f2fd;color:#1976d2}.btn{padding:6px 16px;border:none;border-radius:6px;cursor:pointer}.btn-sm{padding:4px 12px;font-size:11px}.btn-primary{background:#0d7377;color:#fff}</style>